"""Formatting utilities for displaying data in the CLI."""from typing import Listfrom ..models.book import Bookfrom ..models.member import Memberdef format_book_list(books: List[Book]) -> None:    """Display a formatted table of books."""    if not books:        print("\n  No books to display.")        return    print(f"\n  {'Title':<30} {'Author':<20} {'ISBN':<15} {'Status':<12}")    print("  " + "-" * 80)    for book in books:        status = "Available" if book.is_available() else "Checked Out"        # Truncate long strings        title = book.title[:27] + "..." if len(book.title) > 30 else book.title        author = book.author[:17] + "..." if len(book.author) > 20 else book.author        print(f"  {title:<30} {author:<20} {book.isbn:<15} {status:<12}")def format_member_list(members: List[Member]) -> None:    """Display a formatted table of members."""    if not members:        print("\n  No members to display.")        return    print(f"\n  {'Name':<25} {'ID':<12} {'Email':<25} {'Books':<6} {'Fines':<8}")    print("  " + "-" * 80)    for member in members:        name = member.name[:22] + "..." if len(member.name) > 25 else member.name        email = member.email[:22] + "..." if len(member.email) > 25 else member.email        print(f"  {name:<25} {member.member_id:<12} {email:<25} "              f"{member.get_borrowed_count():<6} ${member.get_fines_owed():<7.2f}")def format_loan_list(loans, book_collection, member_collection) -> None:    """Display a formatted table of active loans."""    if not loans:        print("\n  No active loans.")        return    print(f"\n  {'Book':<30} {'Member':<20} {'Due Date':<12} {'Status':<10}")    print("  " + "-" * 75)    for loan in loans:        book = book_collection.find_by_isbn(loan.book_isbn)        member = member_collection.find_by_id(loan.member_id)        book_title = book.title[:27] + "..." if book and len(book.title) > 30 else (book.title if book else "Unknown")        member_name = member.name[:17] + "..." if member and len(member.name) > 20 else (            member.name if member else "Unknown")        overdue = "OVERDUE" if loan.is_overdue() else "Active"        print(f"  {book_title:<30} {member_name:<20} "              f"{loan.due_date.strftime('%Y-%m-%d'):<12} {overdue:<10}")